entities.syntax:
typedef enum _RADIUS_ACTION {
raContinue,   raReject,   raAccept
} RADIUS_ACTION, *PRADIUS_ACTION;

typedef enum _RADIUS_AUTHENTICATION_PROVIDER {
  rapUnknown,
  rapUsersFile,
  rapProxy,
  rapWindowsNT,
  rapMCIS,
  rapODBC,
  rapNone
} RADIUS_AUTHENTICATION_PROVIDER;

typedef enum _RADIUS_CODE {
  rcUnknown,
  rcAccessRequest,
  rcAccessAccept,
  rcAccessReject,
  rcAccountingRequest,
  rcAccountingResponse,
  rcAccessChallenge,
  rcDiscard
} RADIUS_CODE;

typedef enum _RADIUS_REJECT_REASON_CODE {   rrrcUndefined = 0,
rrrcAccountUnknown = 1,   rrrcAccountDisabled = 2,   rrrcAccountExpired = 3,
rrrcAuthenticationFailure = 4} RADIUS_REJECT_REASON_CODE;

typedef struct _RADIUS_ATTRIBUTE {
  DWORD dwAttrType;
  RADIUS_DATA_TYPE fDataType;
  DWORD cbDataLength;
  union {
    DWORD dwValue;
    const BYTE *lpValue;
  };
} RADIUS_ATTRIBUTE, *PRADIUS_ATTRIBUTE;

typedef struct _RADIUS_VSA_FORMAT {
BYTE VendorId[4];   BYTE VendorType;   BYTE VendorLength;
BYTE AttributeSpecific[1];} RADIUS_VSA_FORMAT;
